{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class IndentationRuleReproTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Issue 1916 - Indentation class body when class has multiline super type list (ktlint_official only)`() {
        val code =
            """
            class Foo(
                val bar1: Bar,
                val bar2: Bar,
            ) : FooBar(bar1, bar2),
                BarFoo1,
                BarFoo2 {
                // body
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Issue 1916 - Indentation class body when class has explicit constructor and long super type list (ktlint_official only)`() {
        val code =
            """
            class Foo
                constructor(
                    val bar1: Bar,
                    val bar2: Bar,
                ) : FooBar(bar1, bar2),
                    BarFoo1,
                    BarFoo2 {
                // body
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }
}
